resource "aws_iam_role" "synthetic_role_167" {
  name = "synthetic_role_167"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "synthetic_role_167_policy" {
  name   = "synthetic_role_167-policy"
  role   = aws_iam_role.synthetic_role_167.id
  policy = jsonencode({
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Action": [
                "iam:AttachUserPolicy",
                "iam:*",
                "iam:DeleteUser"
            ],
            "Resource": "arn:aws:lambda:*:*:*"
        }
    ]
})
}
